'use client';

import { useState } from 'react';
import { X, FileUp, AlertCircle, CheckCircle2, Loader2 } from 'lucide-react';
import { useCoursify } from '@/context/CoursifyContext';

export default function ImportBundleModal({ onClose, onImported }) {
  const { refresh } = useCoursify();
  const [file, setFile] = useState(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);
  const [success, setSuccess] = useState(false);

  const handleFileChange = (e) => {
    const selectedFile = e.target.files[0];
    if (selectedFile && selectedFile.type === 'application/json') {
      setFile(selectedFile);
      setError(null);
    } else {
      setFile(null);
      setError('Please select a valid JSON course bundle.');
    }
  };

  const handleImport = async () => {
    if (!file) return;
    setLoading(true);
    setError(null);

    try {
      const text = await file.text();
      const bundle = JSON.parse(text);

      const response = await fetch('/api/coursify/import', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(bundle),
      });

      const result = await response.json();

      if (result.success) {
        setSuccess(true);
        await refresh();
        setTimeout(() => {
          onImported?.(result.courseId);
          onClose();
        }, 1500);
      } else {
        setError(result.error || 'Failed to import course bundle.');
      }
    } catch (err) {
      setError('Invalid JSON file or connection error.');
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  return (
    <>
      <div className="fixed inset-0 z-50 bg-black/30 backdrop-blur-sm" onClick={onClose} />
      <div className="fixed inset-0 z-50 flex items-center justify-center p-4 pointer-events-none">
        <div
          className="bg-white rounded-2xl shadow-2xl w-full max-w-md p-6 pointer-events-auto"
          onClick={(e) => e.stopPropagation()}
        >
          <div className="flex items-center justify-between mb-5">
            <div className="flex items-center gap-2">
              <div className="h-8 w-8 bg-[#1f644e] rounded-lg flex items-center justify-center">
                <FileUp className="w-4 h-4 text-white" />
              </div>
              <h2 className="font-bold text-[#1e3a34] text-lg">Import Course Bundle</h2>
            </div>
            <button
              onClick={onClose}
              className="p-1.5 hover:bg-[#f0f5f2] rounded-lg transition-colors"
            >
              <X className="w-4 h-4 text-[#7c8e88]" />
            </button>
          </div>

          <div className="space-y-4">
            <p className="text-sm text-[#7c8e88]">
              Select a{' '}
              <code className="bg-[#f0f5f2] px-1 rounded text-[#1f644e]">course-bundle.json</code>{' '}
              file generated by the packager script.
            </p>

            <div className="relative group">
              <input
                type="file"
                accept=".json"
                onChange={handleFileChange}
                className="absolute inset-0 w-full h-full opacity-0 cursor-pointer z-10"
              />
              <div
                className={`border-2 border-dashed rounded-2xl p-8 flex flex-col items-center justify-center gap-2 transition-colors ${
                  file
                    ? 'border-[#1f644e] bg-[#f0f5f2]'
                    : 'border-[#e5e3d8] group-hover:border-[#1f644e]/40 bg-[#fcfbf5]'
                }`}
              >
                <FileUp className={`w-8 h-8 ${file ? 'text-[#1f644e]' : 'text-[#b0bfbb]'}`} />
                <span
                  className={`text-sm font-medium ${file ? 'text-[#1e3a34]' : 'text-[#7c8e88]'}`}
                >
                  {file ? file.name : 'Click to browse or drag & drop'}
                </span>
                {file && (
                  <span className="text-[10px] text-[#7c8e88] font-bold uppercase">
                    {(file.size / 1024).toFixed(1)} KB
                  </span>
                )}
              </div>
            </div>

            {error && (
              <div className="flex items-start gap-2 p-3 bg-red-50 rounded-xl text-red-600 text-xs font-medium">
                <AlertCircle className="w-4 h-4 shrink-0" />
                <span>{error}</span>
              </div>
            )}

            {success && (
              <div className="flex items-center gap-2 p-3 bg-green-50 rounded-xl text-green-600 text-xs font-bold">
                <CheckCircle2 className="w-4 h-4 shrink-0" />
                <span>Course imported successfully! Redirecting...</span>
              </div>
            )}

            <div className="flex gap-2 pt-2">
              <button
                type="button"
                onClick={onClose}
                className="flex-1 py-2.5 rounded-xl border border-[#e5e3d8] text-sm font-bold text-[#7c8e88] hover:bg-[#f0f5f2] transition-colors"
              >
                Cancel
              </button>
              <button
                onClick={handleImport}
                disabled={!file || loading || success}
                className="flex-1 flex items-center justify-center gap-2 py-2.5 rounded-xl bg-[#1f644e] text-white text-sm font-bold hover:bg-[#17503e] transition-colors disabled:opacity-50 disabled:cursor-not-allowed"
              >
                {loading ? (
                  <>
                    <Loader2 className="w-4 h-4 animate-spin" />
                    Importing...
                  </>
                ) : (
                  'Import Bundle'
                )}
              </button>
            </div>
          </div>
        </div>
      </div>
    </>
  );
}
